import React from "react";
import "../styles.css";

function Navbar() {
  return (
    <div className="navbar">
      <div className="logo">CourseHub</div>

      <input
        className="search"
        placeholder="Что вы хотите изучить?"
      />

      <button className="login-btn">
        Login
      </button>
    </div>
  );
}

export default Navbar;
